<?php
 declare(strict_types=1); namespace tapmeppe\composer\database\seeders; use App\Models\User; use App\Models\Workspace; use Illuminate\Support\Facades\Hash; use Illuminate\Support\Str; class MarketingAdministrator extends \tapmeppe\composer\helpers\Seeder { public function runInner(array $parameters): bool { if (User::count()) return false; $user = User::create([ 'name' => $parameters['name'], 'email' => $parameters['email'], 'email_verified_at' => now(), 'password' => Hash::make($parameters['password']), 'api_token' => Str::random(80), ]); $workspace = Workspace::create([ 'name' => $parameters['company'], 'owner_id' => $user->id, ]); $user->workspaces()->attach( $workspace, [ 'role' => Workspace::ROLE_OWNER, ] ); return true; } } 